const request = $input.first().json;
const headers = (request.headers && typeof request.headers === 'object' && !Array.isArray(request.headers)) ? request.headers : {};
const headerValue = (value) => Array.isArray(value) ? String(value[0] || '').trim() : String(value || '').trim();
const expectedApiKey = String($env.N8N_WEBHOOK_API_KEY || '').trim();
const xApiKey = headerValue(headers['x-api-key'] ?? headers['X-API-Key']);
const authorization = headerValue(headers.authorization ?? headers.Authorization);
const bearerMatch = authorization.match(/^Bearer\s+(.+)$/i);
const bearerToken = bearerMatch ? String(bearerMatch[1] || '').trim() : '';
const authenticated = Boolean(expectedApiKey) && (xApiKey === expectedApiKey || bearerToken === expectedApiKey);

if (authenticated) {
  return [{
    json: {
      ...request,
      webhook_auth: {
        authenticated: true,
        header: xApiKey ? 'X-API-Key' : 'Authorization'
      }
    }
  }];
}

const message = expectedApiKey
  ? 'Unauthorized: Invalid or missing API key'
  : 'Unauthorized: N8N_WEBHOOK_API_KEY is not configured';

return [{
  json: {
    ...request,
    status: 'error',
    message,
    code: 401,
    webhook_auth: {
      authenticated: false
    }
  }
}];

const input = $input.first().json.body || {};

if (!input.request_id || !input.decision || !input.approver) {
  return [{ json: { status: 'error', message: 'Missing required fields: request_id, decision, approver' } }];
}

const validDecisions = ['approved', 'rejected'];
if (!validDecisions.includes(input.decision)) {
  return [{ json: { status: 'error', message: 'decision must be approved or rejected' } }];
}

return [{
  json: {
    request_id: String(input.request_id),
    decision: input.decision,
    approver: String(input.approver),
    comment: String(input.comment || ''),
    approved_at: new Date().toISOString(),
    policy_id: String(input.policy_id || 'unknown'),
    policy_version: String(input.policy_version || 'unknown')
  }
}];

const data = $input.first().json;
if (data.status === 'error') {
  return [{ json: data }];
}

const auditDecision = data.decision === 'approved' ? 'allowed' : 'denied';
return [{ json: { ...data, auditDecision } }];
